const sharp = require\('sharp'\);
const fs = require\('fs'\);
const path = require\('path'\);

const dir = 'public/images/posts';

function getImages\(dir\) {
  let results = [];
  for \(const entry of fs.readdirSync\(dir, { withFileTypes: true }\)\) {
    const full = path.join\(dir, entry.name\);
    if \(entry.isDirectory\(\)\) results = results.concat\(getImages\(full\)\);
    else if \(/\\.\(jpg|jpeg\)$/i.test\(entry.name\)\) results.push\(full\);
  }
  return results;
}

const images = getImages\(dir\);
console.log\('Found', images.length, 'images'\);

Promise.all\(images.map\(async img => {
  const before = fs.statSync\(img\).size;
  const tmp = img + '.tmp';
  await sharp\(img\).jpeg\({ quality: 80, progressive: true }\).toFile\(tmp\);
  fs.renameSync\(tmp, img\);
  const after = fs.statSync\(img\).size;
  console.log\(path.basename\(img\), Math.round\(before/1024\) + 'KB →', Math.round\(after/1024\) + 'KB'\);
}\)\).then\(\(\) => console.log\('Done'\)\);
